import kotlinx.datetime.*
import kotlinx.datetime.format.*

fun testInstantParse() {
    println("Testing Instant.parse consistency...")

    // Test 1: String with seconds (should work on all platforms)
    try {
        val instant1 = Instant.parse("2024-03-19T17:50:15Z")
        println("✓ Test 1 PASSED: Parsing with seconds works: $instant1")
    } catch (e: Exception) {
        println("✗ Test 1 FAILED: Error parsing with seconds: ${e.message}")
    }

    // Test 2: String without seconds (should fail on all platforms per documentation)
    try {
        val instant2 = Instant.parse("2024-03-19T17:50Z")
        println("✗ Test 2 FAILED: Parsing without seconds should have failed but got: $instant2")
    } catch (e: Exception) {
        println("✓ Test 2 PASSED: Parsing without seconds correctly fails: ${e.javaClass.simpleName}")
    }

    // Test 3: String with fractional seconds (should work)
    try {
        val instant3 = Instant.parse("2024-03-19T17:50:15.123Z")
        println("✓ Test 3 PASSED: Parsing with fractional seconds works: $instant3")
    } catch (e: Exception) {
        println("✗ Test 3 FAILED: Error parsing with fractional seconds: ${e.message}")
    }

    // Test 4: String with offset
    try {
        val instant4 = Instant.parse("2024-03-19T17:50:15+03:00")
        println("✓ Test 4 PASSED: Parsing with offset works: $instant4")
    } catch (e: Exception) {
        println("✗ Test 4 FAILED: Error parsing with offset: ${e.message}")
    }

    // Test 5: Verify behavior is consistent with DateTimeComponents
    try {
        val components = DateTimeComponents.Formats.ISO_DATE_TIME_OFFSET.parse("2024-03-19T17:50Z")
        println("✗ Test 5 FAILED: DateTimeComponents should require seconds but parsed without them")
    } catch (e: Exception) {
        println("✓ Test 5 PASSED: DateTimeComponents correctly rejects string without seconds: ${e.javaClass.simpleName}")
    }

    println("\nAll tests completed")
}

fun main() {
    testInstantParse()
}"}

